// ========================================================================
// helpers (visibles à templ : exportés ou minuscules — minuscules ici car
// templ-internes ; les fonctions appelées depuis les templates DOIVENT être
// dans le même package).
// ========================================================================

func inputType(t string) string {
	switch t {
	case "email":
		return "email"
	case "tel":
		return "tel"
	default:
		return "text"
	}
}

func pluralize(n int, sing, plur string) string {
	if n == 1 {
		return "1 " + sing
	}
	return itoa(n) + " " + plur
}

func itoa(n int) string {
	// minimal int→string sans alloc côté templ.
	if n == 0 {
		return "0"
	}
	neg := false
	if n < 0 {
		neg = true
		n = -n
	}
	buf := [20]byte{}
	i := len(buf)
	for n > 0 {
		i--
		buf[i] = byte('0' + n%10)
		n /= 10
	}
	if neg {
		i--
		buf[i] = '-'
	}
	return string(buf[i:])
}

// highlightSafe : trim et passe-plat (FTS5 snippet déjà sécurisé côté
// search.Engine — pas de re-échappement nécessaire).
func highlightSafe(s string) string {
	return strings.TrimSpace(s)
}

